package org.guy.library.clients

/**
 * Common interface for all underlying AI model clients.
 */
interface AiClient {
    /**
     * Sends a simple text prompt to the AI model and returns the text response.
     * @param prompt The user's input prompt.
     * @return The text content generated by the AI model.
     * @throws Exception If an error occurs during the API call or parsing.
     */
    fun generate(prompt: String): String

    /**
     * Sends a prompt and requests the AI to return data that matches the structure of [type].
     * @param prompt The user's input prompt.
     * @param type The Type to deserialize the AI's response into.
     * @return An instance of [T] parsed from the AI response.
     * @throws Exception If an error occurs during API call, generating JSON, or parsing.
     */
    fun <T> generateObject(prompt: String, type: java.lang.reflect.Type): T

    /**
     * Optional callback to receive token usage statistics after a successful API call.
     */
    var onTokenUsage: ((inputTokens: Int, outputTokens: Int) -> Unit)?
}
